/**
 * Input Modality Tracker
 * 
 * Detects if the user is interacting with the keyboard or mouse.
 * Adds '.keyboard-user' class to the body when Tabbing is detected.
 * Removes it on mouse interaction.
 */
export function initInputModality() {
  if (typeof document === 'undefined') return;

  const handleFirstTab = (e) => {
    if (e.key === 'Tab') {
      document.body.classList.add('keyboard-user');
      window.removeEventListener('keydown', handleFirstTab);
      window.addEventListener('mousedown', handleMouseDown);
    }
  };

  const handleMouseDown = () => {
    document.body.classList.remove('keyboard-user');
    window.removeEventListener('mousedown', handleMouseDown);
    window.addEventListener('keydown', handleFirstTab);
  };

  window.addEventListener('keydown', handleFirstTab);
}
